import { NextRequest, NextResponse } from "next/server";
import nodemailer from "nodemailer";

const transporter = nodemailer.createTransport({
  host: process.env.SMTP_HOST || "smtp.gmail.com",
  port: Number(process.env.SMTP_PORT) || 587,
  secure: false,
  auth: {
    user: process.env.SMTP_USER || "tanjimmahmudrakin2@gmail.com",
    pass: process.env.SMTP_PASS,
  },
});

export async function POST(req: NextRequest) {
  try {
    const { name, email, subject, message } = await req.json();

    if (!name || !email || !message) {
      return NextResponse.json({ error: "Name, email, and message are required" }, { status: 400 });
    }

    // Try to save to backend DB
    const apiUrl = process.env.BICTA_API_URL;
    if (apiUrl) {
      try {
        await fetch(`${apiUrl}/trpc/contact.submit`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ json: { name, email, subject, message } }),
        });
      } catch { /* backend offline — email fallback below */ }
    }

    // Always send email notification
    await transporter.sendMail({
      from: `BICTA Contact <${process.env.SMTP_USER || "tanjimmahmudrakin2@gmail.com"}>`,
      to: process.env.SMTP_USER || "tanjimmahmudrakin2@gmail.com",
      subject: `[BICTA Contact] ${subject || "New message"} — from ${name}`,
      html: `
        <h2>New Contact Form Submission</h2>
        <p><strong>Name:</strong> ${name}</p>
        <p><strong>Email:</strong> ${email}</p>
        <p><strong>Subject:</strong> ${subject || "N/A"}</p>
        <hr/>
        <p>${message.replace(/\n/g, "<br/>")}</p>
      `,
      replyTo: email,
    });

    return NextResponse.json({ ok: true });
  } catch (e) {
    console.error("Contact form error:", e);
    return NextResponse.json({ error: "Failed to send message" }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";
import nodemailer from "nodemailer";

const transporter = nodemailer.createTransport({
  host: process.env.SMTP_HOST || "smtp.gmail.com",
  port: Number(process.env.SMTP_PORT) || 587,
  secure: false,
  auth: {
    user: process.env.SMTP_USER || "tanjimmahmudrakin2@gmail.com",
    pass: process.env.SMTP_PASS,
  },
});

export async function POST(req: NextRequest) {
  try {
    const { name, email, company, partnershipType, message } = await req.json();

    if (!name || !email || !company) {
      return NextResponse.json({ error: "Name, email, and company are required" }, { status: 400 });
    }

    const apiUrl = process.env.BICTA_API_URL;
    if (apiUrl) {
      try {
        await fetch(`${apiUrl}/trpc/partner.submitInquiry`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ json: { name, email, company, partnershipType, message } }),
        });
      } catch { /* fallback to email */ }
    }

    await transporter.sendMail({
      from: `BICTA <${process.env.SMTP_USER || "tanjimmahmudrakin2@gmail.com"}>`,
      to: process.env.SMTP_USER || "tanjimmahmudrakin2@gmail.com",
      subject: `[BICTA Partner] New inquiry from ${company}`,
      html: `
        <h2>New Partnership Inquiry</h2>
        <p><strong>Name:</strong> ${name}</p>
        <p><strong>Email:</strong> ${email}</p>
        <p><strong>Company:</strong> ${company}</p>
        <p><strong>Partnership type:</strong> ${partnershipType || "N/A"}</p>
        <hr/>
        <p>${(message || "").replace(/\n/g, "<br/>")}</p>
      `,
      replyTo: email,
    });

    return NextResponse.json({ ok: true });
  } catch (e) {
    console.error("Partner inquiry error:", e);
    return NextResponse.json({ error: "Failed to send inquiry" }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";

export async function POST(req: NextRequest) {
  try {
    const body = await req.json();
    const { sessionId, answers, violations } = body;
    const token = req.cookies.get("bicta_token")?.value;

    // Try backend first
    const apiUrl = process.env.BICTA_API_URL;
    if (apiUrl && token) {
      try {
        const res = await fetch(`${apiUrl}/trpc/competition.submit`, {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            Cookie: `bicta_token=${token}`,
          },
          body: JSON.stringify({ json: { sessionId, answers, violations } }),
        });
        if (res.ok) {
          const data = await res.json();
          return NextResponse.json({ ok: true, result: data?.result?.data });
        }
      } catch { /* fallback below */ }
    }

    // Fallback: calculate score client-side and return
    // (Admin can review violation logs)
    return NextResponse.json({
      ok: true,
      result: {
        status: "submitted",
        message: "Exam submitted. Results will be published by the admin.",
        fallback: true,
      },
    });
  } catch (e) {
    console.error("Exam submit error:", e);
    return NextResponse.json({ error: "Submission failed" }, { status: 500 });
  }
}
